-- ============================================================
-- Hardware Store Database - PostgreSQL
-- Generated for analytics, KPIs, and reporting. 
-- ============================================================
-- Summary: 350 products | 700 customers
-- 12000 sales orders | 47363 line items
-- 1200 supplier orders | 2732 supplier line items
-- ============================================================

BEGIN;


-- ============================================================
-- DROP (safe re-run)
-- ============================================================
DROP TABLE IF EXISTS supplier_order_items CASCADE;
DROP TABLE IF EXISTS supplier_orders CASCADE;
DROP TABLE IF EXISTS sales_order_items CASCADE;
DROP TABLE IF EXISTS sales_orders CASCADE;
DROP TABLE IF EXISTS inventory CASCADE;
DROP TABLE IF EXISTS products CASCADE;
DROP TABLE IF EXISTS customers CASCADE;
DROP TABLE IF EXISTS suppliers CASCADE;
DROP TABLE IF EXISTS employees CASCADE;
DROP TABLE IF EXISTS departments CASCADE;

-- ============================================================
-- TABLES
-- ============================================================

CREATE TABLE departments (
    department_id   SERIAL PRIMARY KEY,
    name            VARCHAR(60) NOT NULL,
    manager_employee_id INT  -- FK added after employees
);

CREATE TABLE employees (
    employee_id     SERIAL PRIMARY KEY,
    first_name      VARCHAR(50) NOT NULL,
    last_name       VARCHAR(50) NOT NULL,
    role            VARCHAR(40) NOT NULL,
    hire_date       DATE NOT NULL,
    department_id   INT REFERENCES departments(department_id),
    hourly_rate     NUMERIC(6,2) NOT NULL
);

ALTER TABLE departments
    ADD CONSTRAINT fk_dept_manager
    FOREIGN KEY (manager_employee_id) REFERENCES employees(employee_id);

CREATE TABLE suppliers (
    supplier_id     SERIAL PRIMARY KEY,
    supplier_name   VARCHAR(100) NOT NULL,
    contact_name    VARCHAR(80),
    phone           VARCHAR(20),
    email           VARCHAR(100),
    lead_time_days  INT NOT NULL
);

CREATE TABLE products (
    product_id          SERIAL PRIMARY KEY,
    product_name        VARCHAR(120) NOT NULL,
    department_id       INT REFERENCES departments(department_id),
    supplier_id         INT REFERENCES suppliers(supplier_id),
    sku                 VARCHAR(20) UNIQUE NOT NULL,
    unit_cost           NUMERIC(10,2) NOT NULL,
    unit_price          NUMERIC(10,2) NOT NULL,
    reorder_point       INT NOT NULL DEFAULT 10,
    is_special_order    BOOLEAN NOT NULL DEFAULT FALSE,
    is_discontinued     BOOLEAN NOT NULL DEFAULT FALSE
);

CREATE TABLE inventory (
    inventory_id        SERIAL PRIMARY KEY,
    product_id          INT UNIQUE REFERENCES products(product_id),
    quantity_on_hand    INT NOT NULL DEFAULT 0,
    quantity_on_order   INT NOT NULL DEFAULT 0,
    last_restock_date   DATE
);

CREATE TABLE customers (
    customer_id     SERIAL PRIMARY KEY,
    first_name      VARCHAR(50) NOT NULL,
    last_name       VARCHAR(50) NOT NULL,
    customer_type   VARCHAR(20) NOT NULL CHECK (customer_type IN ('Homeowner','Contractor','Business')),
    email           VARCHAR(100),
    phone           VARCHAR(20),
    join_date       DATE NOT NULL
);

CREATE TABLE sales_orders (
    order_id        SERIAL PRIMARY KEY,
    customer_id     INT REFERENCES customers(customer_id),
    employee_id     INT REFERENCES employees(employee_id),
    order_date      TIMESTAMP NOT NULL,
    payment_method  VARCHAR(20) NOT NULL CHECK (payment_method IN ('Cash','Credit','Debit','Store Account')),
    order_total     NUMERIC(10,2) NOT NULL DEFAULT 0
);

CREATE TABLE sales_order_items (
    order_item_id       SERIAL PRIMARY KEY,
    order_id            INT REFERENCES sales_orders(order_id),
    product_id          INT REFERENCES products(product_id),
    quantity            INT NOT NULL,
    unit_price_at_sale  NUMERIC(10,2) NOT NULL,
    discount_amount     NUMERIC(10,2) NOT NULL DEFAULT 0
);

CREATE TABLE supplier_orders (
    supplier_order_id       SERIAL PRIMARY KEY,
    supplier_id             INT REFERENCES suppliers(supplier_id),
    employee_id             INT REFERENCES employees(employee_id),
    order_date              DATE NOT NULL,
    expected_delivery_date  DATE NOT NULL,
    status                  VARCHAR(20) NOT NULL CHECK (status IN ('Pending','Shipped','Received'))
);

CREATE TABLE supplier_order_items (
    supplier_order_item_id  SERIAL PRIMARY KEY,
    supplier_order_id       INT REFERENCES supplier_orders(supplier_order_id),
    product_id              INT REFERENCES products(product_id),
    quantity_ordered        INT NOT NULL,
    unit_cost_at_order      NUMERIC(10,2) NOT NULL
);

