-- ============================================================
-- INDEXES for query performance
-- ============================================================
CREATE INDEX idx_products_dept        ON products(department_id);
CREATE INDEX idx_products_supplier    ON products(supplier_id);
CREATE INDEX idx_inventory_product    ON inventory(product_id);
CREATE INDEX idx_sales_orders_date    ON sales_orders(order_date);
CREATE INDEX idx_sales_orders_cust    ON sales_orders(customer_id);
CREATE INDEX idx_sales_orders_emp     ON sales_orders(employee_id);
CREATE INDEX idx_soi_order            ON sales_order_items(order_id);
CREATE INDEX idx_soi_product          ON sales_order_items(product_id);
CREATE INDEX idx_sup_orders_supplier  ON supplier_orders(supplier_id);
CREATE INDEX idx_sup_order_items_prod ON supplier_order_items(product_id);


-- ============================================================
-- SAMPLE ANALYTIC VIEWS
-- ============================================================

-- Revenue by department
CREATE OR REPLACE VIEW vw_revenue_by_dept AS
SELECT d.name AS department,
       SUM(soi.quantity * soi.unit_price_at_sale - soi.discount_amount) AS total_revenue,
       COUNT(DISTINCT so.order_id) AS order_count
FROM sales_order_items soi
JOIN sales_orders so  ON so.order_id  = soi.order_id
JOIN products p       ON p.product_id = soi.product_id
JOIN departments d    ON d.department_id = p.department_id
GROUP BY d.name;

-- Gross margin by product
CREATE OR REPLACE VIEW vw_product_margin AS
SELECT p.product_id, p.product_name, d.name AS department,
       SUM(soi.quantity * soi.unit_price_at_sale - soi.discount_amount) AS revenue,
       SUM(soi.quantity * p.unit_cost)                                   AS cogs,
       SUM(soi.quantity * soi.unit_price_at_sale - soi.discount_amount)
         - SUM(soi.quantity * p.unit_cost)                               AS gross_profit,
       ROUND(
         (SUM(soi.quantity * soi.unit_price_at_sale - soi.discount_amount)
          - SUM(soi.quantity * p.unit_cost))
         / NULLIF(SUM(soi.quantity * soi.unit_price_at_sale - soi.discount_amount),0) * 100
       , 2) AS margin_pct
FROM sales_order_items soi
JOIN products p    ON p.product_id    = soi.product_id
JOIN departments d ON d.department_id = p.department_id
GROUP BY p.product_id, p.product_name, d.name;

-- Seasonal sales trend
CREATE OR REPLACE VIEW vw_seasonal_trend AS
SELECT d.name AS department,
       EXTRACT(YEAR  FROM so.order_date)::INT AS yr,
       EXTRACT(MONTH FROM so.order_date)::INT AS mo,
       SUM(soi.quantity * soi.unit_price_at_sale - soi.discount_amount) AS revenue
FROM sales_order_items soi
JOIN sales_orders so ON so.order_id   = soi.order_id
JOIN products p      ON p.product_id  = soi.product_id
JOIN departments d   ON d.department_id = p.department_id
GROUP BY d.name, yr, mo
ORDER BY d.name, yr, mo;

-- Inventory health
CREATE OR REPLACE VIEW vw_inventory_health AS
SELECT p.product_id, p.product_name, d.name AS department,
       i.quantity_on_hand, i.quantity_on_order, p.reorder_point,
       CASE
         WHEN i.quantity_on_hand = 0                  THEN 'Out of Stock'
         WHEN i.quantity_on_hand < p.reorder_point    THEN 'Below Reorder'
         WHEN i.quantity_on_hand > p.reorder_point*8  THEN 'Overstocked'
         ELSE 'Normal'
       END AS stock_status
FROM inventory i
JOIN products p    ON p.product_id    = i.product_id
JOIN departments d ON d.department_id = p.department_id;

-- Employee sales performance
CREATE OR REPLACE VIEW vw_employee_sales AS
SELECT e.employee_id,
       e.first_name || ' ' || e.last_name AS employee_name,
       e.role, d.name AS department,
       COUNT(DISTINCT so.order_id) AS orders_handled,
       SUM(so.order_total)         AS total_sales
FROM sales_orders so
JOIN employees e   ON e.employee_id   = so.employee_id
JOIN departments d ON d.department_id = e.department_id
GROUP BY e.employee_id, employee_name, e.role, d.name;

-- Customer lifetime value
CREATE OR REPLACE VIEW vw_customer_ltv AS
SELECT c.customer_id,
       c.first_name || ' ' || c.last_name AS customer_name,
       c.customer_type,
       COUNT(DISTINCT so.order_id) AS total_orders,
       SUM(so.order_total)         AS lifetime_value,
       AVG(so.order_total)         AS avg_order_value,
       MIN(so.order_date)          AS first_order,
       MAX(so.order_date)          AS last_order
FROM customers c
JOIN sales_orders so ON so.customer_id = c.customer_id
GROUP BY c.customer_id, customer_name, c.customer_type;

-- Supplier on-time delivery
CREATE OR REPLACE VIEW vw_supplier_delivery AS
SELECT s.supplier_id, s.supplier_name,
       COUNT(*)                                                   AS total_orders,
       SUM(CASE WHEN so.status = 'Received' THEN 1 ELSE 0 END)   AS received,
       ROUND(AVG(so.expected_delivery_date - so.order_date), 1)   AS avg_lead_days
FROM supplier_orders so
JOIN suppliers s ON s.supplier_id = so.supplier_id
GROUP BY s.supplier_id, s.supplier_name;

COMMIT;

